# Explorer: complete from packet starter + instruction contract
def assess(record: dict) -> str:
    required = {"case_id", 'unit', 'target', 'horizon'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not ("fraud" in record["target"]) else "REJECT_FRAUD_TARGET"

valid = {"case_id": "CASO-LIM-033-1A", **{'unit': 'entity_pair', 'target': 'needs_review_7d', 'horizon': 7}}
invalid = {"case_id": "CASO-LIM-033-1A", **{'unit': 'entity_pair', 'target': 'is_fraud', 'horizon': 7}}
incomplete = {**valid}
incomplete.pop("horizon")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
print(assess(valid))
missing = {k: valid[k] for k in valid if k != 'horizon'}
print(assess(missing))

